import React, { Component, ErrorInfo, ReactNode } from "react";
import { AlertTriangle, RefreshCw, Home, Bug } from "lucide-react";

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
  retryCount: number;
}

interface ErrorBoundaryProps {
  children: ReactNode;
  fallback?: ReactNode;
  onError?: (error: Error, errorInfo: ErrorInfo) => void;
  maxRetries?: number;
}

export class ErrorBoundary extends Component<
  ErrorBoundaryProps,
  ErrorBoundaryState
> {
  private readonly retryTimeoutId: NodeJS.Timeout | null = null;

  constructor(props: ErrorBoundaryProps) {
    super(props);
    this.state = {
      hasError: false,
      error: null,
      retryCount: 0,
    };
  }

  static getDerivedStateFromError(error: Error): Partial<ErrorBoundaryState> {
    return {
      hasError: true,
      error,
    };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    this.setState({
      error,
    });

    // Call the onError callback if provided
    this.props.onError?.(error, errorInfo);

    // Log error to console in development
    if (process.env.NODE_ENV === "development") {
      console.error("ErrorBoundary caught an error:", error, errorInfo);
    }
  }

  componentWillUnmount() {
    if (this.retryTimeoutId) {
      clearTimeout(this.retryTimeoutId);
    }
  }

  handleRetry = () => {
    const { maxRetries = 3 } = this.props;
    const { retryCount } = this.state;

    if (retryCount < maxRetries) {
      this.setState((prevState) => ({
        hasError: false,
        error: null,
        retryCount: prevState.retryCount + 1,
      }));
    }
  };

  handleReset = () => {
    this.setState({
      hasError: false,
      error: null,
      retryCount: 0,
    });
  };

  handleGoHome = () => {
    window.location.href = "/";
  };

  render() {
    const { hasError, error, retryCount } = this.state;
    const { children, fallback, maxRetries = 3 } = this.props;

    if (hasError) {
      if (fallback) {
        return fallback;
      }

      return (
        <div
          style={{
            minHeight: "100vh",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            padding: "1rem",
            backgroundColor: "#111827",
          }}
        >
          <div style={{ maxWidth: "28rem", width: "100%" }}>
            <div
              style={{
                backgroundColor: "#1f2937",
                border: "1px solid #374151",
                borderRadius: "1rem",
                padding: "2rem",
                textAlign: "center",
              }}
            >
              {/* Error Icon */}
              <div
                style={{
                  display: "flex",
                  justifyContent: "center",
                  marginBottom: "1.5rem",
                }}
              >
                <div
                  style={{
                    padding: "1rem",
                    backgroundColor: "rgba(239, 68, 68, 0.1)",
                    borderRadius: "50%",
                  }}
                >
                  <AlertTriangle
                    style={{ width: "3rem", height: "3rem", color: "#ef4444" }}
                  />
                </div>
              </div>

              {/* Error Title */}
              <div style={{ marginBottom: "1.5rem" }}>
                <h2
                  style={{
                    fontSize: "1.5rem",
                    fontWeight: "bold",
                    color: "white",
                    marginBottom: "0.5rem",
                  }}
                >
                  Oops! Something went wrong
                </h2>
                <p style={{ color: "#d1d5db" }}>
                  We encountered an unexpected error. Don't worry, we're on it!
                </p>
              </div>

              {/* Error Details (Development Only) */}
              {process.env.NODE_ENV === "development" && error && (
                <details
                  style={{
                    textAlign: "left",
                    backgroundColor: "#374151",
                    borderRadius: "0.5rem",
                    padding: "1rem",
                    marginBottom: "1.5rem",
                  }}
                >
                  <summary
                    style={{
                      cursor: "pointer",
                      fontSize: "0.875rem",
                      fontWeight: "500",
                      color: "#d1d5db",
                      marginBottom: "0.5rem",
                    }}
                  >
                    Error Details (Development)
                  </summary>
                  <pre
                    style={{
                      fontSize: "0.75rem",
                      color: "#9ca3af",
                      overflow: "auto",
                      maxHeight: "8rem",
                    }}
                  >
                    {error.message}
                    {error.stack && `\n\n${error.stack}`}
                  </pre>
                </details>
              )}

              {/* Action Buttons */}
              <div
                style={{
                  display: "flex",
                  flexDirection: "column",
                  gap: "0.75rem",
                }}
              >
                {retryCount < maxRetries && (
                  <button
                    type="button"
                    onClick={this.handleRetry}
                    style={{
                      flex: 1,
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      gap: "0.5rem",
                      padding: "0.75rem 1rem",
                      backgroundColor: "#3b82f6",
                      color: "white",
                      borderRadius: "0.75rem",
                      border: "none",
                      cursor: "pointer",
                      fontWeight: "500",
                    }}
                    onMouseOver={(e) => {
                      const t = e.target as HTMLElement | null;
                      if (t) t.style.backgroundColor = "#2563eb";
                    }}
                    onMouseOut={(e) => {
                      const t = e.target as HTMLElement | null;
                      if (t) t.style.backgroundColor = "#3b82f6";
                    }}
                    onFocus={(e) => {
                      const t = e.target as HTMLElement | null;
                      if (t) t.style.backgroundColor = "#2563eb";
                    }}
                    onBlur={(e) => {
                      const t = e.target as HTMLElement | null;
                      if (t) t.style.backgroundColor = "#3b82f6";
                    }}
                  >
                    <RefreshCw style={{ width: "1rem", height: "1rem" }} />
                    Try Again ({maxRetries - retryCount} left)
                  </button>
                )}

                <button
                  type="button"
                  onClick={this.handleReset}
                  style={{
                    flex: 1,
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    gap: "0.5rem",
                    padding: "0.75rem 1rem",
                    backgroundColor: "#374151",
                    color: "white",
                    borderRadius: "0.75rem",
                    border: "1px solid #4b5563",
                    cursor: "pointer",
                    fontWeight: "500",
                  }}
                  onMouseOver={(e) => {
                    const t = e.target as HTMLElement | null;
                    if (t) t.style.backgroundColor = "#4b5563";
                  }}
                  onMouseOut={(e) => {
                    const t = e.target as HTMLElement | null;
                    if (t) t.style.backgroundColor = "#374151";
                  }}
                  onFocus={(e) => {
                    const t = e.target as HTMLElement | null;
                    if (t) t.style.backgroundColor = "#4b5563";
                  }}
                  onBlur={(e) => {
                    const t = e.target as HTMLElement | null;
                    if (t) t.style.backgroundColor = "#374151";
                  }}
                >
                  <Bug style={{ width: "1rem", height: "1rem" }} />
                  Reset
                </button>

                <button
                  type="button"
                  onClick={this.handleGoHome}
                  style={{
                    flex: 1,
                    display: "flex",
                    alignItems: "center",
                    justifyContent: "center",
                    gap: "0.5rem",
                    padding: "0.75rem 1rem",
                    backgroundColor: "#374151",
                    color: "white",
                    borderRadius: "0.75rem",
                    border: "1px solid #4b5563",
                    cursor: "pointer",
                    fontWeight: "500",
                  }}
                  onMouseOver={(e) => {
                    const t = e.target as HTMLElement | null;
                    if (t) t.style.backgroundColor = "#4b5563";
                  }}
                  onMouseOut={(e) => {
                    const t = e.target as HTMLElement | null;
                    if (t) t.style.backgroundColor = "#374151";
                  }}
                  onFocus={(e) => {
                    const t = e.target as HTMLElement | null;
                    if (t) t.style.backgroundColor = "#4b5563";
                  }}
                  onBlur={(e) => {
                    const t = e.target as HTMLElement | null;
                    if (t) t.style.backgroundColor = "#374151";
                  }}
                >
                  <Home style={{ width: "1rem", height: "1rem" }} />
                  Go Home
                </button>
              </div>

              {/* Retry Count Info */}
              {retryCount > 0 && (
                <p
                  style={{
                    fontSize: "0.875rem",
                    color: "#9ca3af",
                    marginTop: "1rem",
                  }}
                >
                  Retry attempt: {retryCount}/{maxRetries}
                </p>
              )}
            </div>
          </div>
        </div>
      );
    }

    return children;
  }
}

// Hook for functional components to trigger error boundary
export function useErrorHandler() {
  return (error: Error) => {
    // This will be caught by the nearest ErrorBoundary
    throw error;
  };
}

// Higher-order component for easier error boundary wrapping
export function withErrorBoundary<P extends object>(
  Wrapped: React.ComponentType<P>,
  errorBoundaryProps?: Omit<ErrorBoundaryProps, "children">,
) {
  function WrappedComponent(props: P) {
    return (
      <ErrorBoundary {...errorBoundaryProps}>
        <Wrapped {...props} />
      </ErrorBoundary>
    );
  }

  WrappedComponent.displayName = `withErrorBoundary(${Wrapped.displayName || Wrapped.name})`;

  return WrappedComponent;
}

import React, { useState, useRef, useEffect } from "react";
import { ChevronDown, Check } from "lucide-react";
import { cn } from "#/utils/utils";

export interface DropdownItem {
  key: string;
  label: string;
  disabled?: boolean;
}

export interface DropdownSection {
  title: string;
  items: DropdownItem[];
}

interface CustomDropdownProps {
  items: DropdownItem[] | DropdownSection[];
  value?: string;
  placeholder?: string;
  disabled?: boolean;
  className?: string;
  inputClassName?: string;
  onSelectionChange?: (key: string) => void;
  onInputChange?: (value: string) => void;
  isClearable?: boolean;
  "data-testid"?: string;
  "aria-label"?: string;
  isLoading?: boolean;
  loadingText?: string;
  error?: string;
}

export function CustomDropdown({
  items,
  value,
  placeholder = "Select an option",
  disabled = false,
  className,
  inputClassName,
  onSelectionChange,
  onInputChange,
  isClearable = false,
  "data-testid": testId,
  "aria-label": ariaLabel,
  isLoading = false,
  loadingText = "Loading...",
  error,
}: CustomDropdownProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [inputValue, setInputValue] = useState(value || "");
  const [filteredItems, setFilteredItems] = useState(items);
  const [selectedKey, setSelectedKey] = useState(value || "");
  const dropdownRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Handle click outside to close dropdown
  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (
        dropdownRef.current &&
        !dropdownRef.current.contains(event.target as Node)
      ) {
        setIsOpen(false);
      }
    }

    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Handle escape key to close dropdown
  useEffect(() => {
    function handleEscape(event: KeyboardEvent) {
      if (event.key === "Escape") {
        setIsOpen(false);
        inputRef.current?.blur();
      }
    }

    if (isOpen) {
      document.addEventListener("keydown", handleEscape);
      return () => document.removeEventListener("keydown", handleEscape);
    }
  }, [isOpen]);

  // Filter items based on input
  useEffect(() => {
    if (!inputValue.trim()) {
      setFilteredItems(items);
      return;
    }

    const filterItems = (
      list: DropdownItem[] | DropdownSection[],
    ): DropdownItem[] | DropdownSection[] => {
      if (Array.isArray(list) && list.length > 0 && "key" in list[0]) {
        // It's DropdownItem[]
        return (list as DropdownItem[]).filter((it) =>
          it.label.toLowerCase().includes(inputValue.toLowerCase()),
        );
      }
      // It's DropdownSection[]
      return (list as DropdownSection[])
        .map((section) => ({
          ...section,
          items: section.items.filter((it) =>
            it.label.toLowerCase().includes(inputValue.toLowerCase()),
          ),
        }))
        .filter((section) => section.items.length > 0);
    };

    setFilteredItems(filterItems(items));
  }, [inputValue, items]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newValue = e.target.value;
    setInputValue(newValue);
    onInputChange?.(newValue);

    if (!isOpen) {
      setIsOpen(true);
    }
  };

  const handleItemClick = (key: string, label: string) => {
    setSelectedKey(key);
    setInputValue(label);
    setIsOpen(false);
    onSelectionChange?.(key);
  };

  const handleItemClickFor = (item: DropdownItem) => () => {
    if (!item.disabled) handleItemClick(item.key, item.label);
  };

  const handleInputFocus = () => {
    if (!disabled) {
      setIsOpen(true);
    }
  };

  // Reuse focus handler for click to avoid duplicate logic
  const handleInputClick = handleInputFocus;

  const handleClear = (e: React.MouseEvent) => {
    e.stopPropagation();
    setSelectedKey("");
    setInputValue("");
    onSelectionChange?.("");
  };

  // Helper removed: getSelectedLabel was unused. The component keeps selectedKey
  // and displays the selected label inline where needed.

  const renderItems = () => {
    if (
      Array.isArray(filteredItems) &&
      filteredItems.length > 0 &&
      "key" in filteredItems[0]
    ) {
      // Render simple items
      return (filteredItems as DropdownItem[]).map((item) => (
        <button
          key={item.key}
          type="button"
          className={cn(
            "w-full text-left px-4 py-3 text-sm transition-all duration-200",
            "hover:bg-primary-500/10 hover:text-text-primary",
            "focus:bg-primary-500/10 focus:text-text-primary focus:outline-none",
            selectedKey === item.key && "bg-primary-500/20 text-text-primary",
            item.disabled && "opacity-50 cursor-not-allowed",
            !item.disabled && "cursor-pointer",
          )}
          onClick={handleItemClickFor(item)}
          disabled={item.disabled}
        >
          <div className="flex items-center justify-between">
            <span>{item.label}</span>
            {selectedKey === item.key && (
              <Check className="w-4 h-4 text-primary-500" />
            )}
          </div>
        </button>
      ));
    }
    // Render sections
    return (filteredItems as DropdownSection[]).map((section) => (
      <div key={section.title || section.items[0]?.key}>
        <div className="px-4 py-2 text-xs font-medium text-text-secondary border-b border-border-subtle/50">
          {section.title}
        </div>
        {section.items.map((item) => (
          <button
            key={item.key}
            type="button"
            className={cn(
              "w-full text-left px-4 py-3 text-sm transition-all duration-200",
              "hover:bg-primary-500/10 hover:text-text-primary",
              "focus:bg-primary-500/10 focus:text-text-primary focus:outline-none",
              selectedKey === item.key && "bg-primary-500/20 text-text-primary",
              item.disabled && "opacity-50 cursor-not-allowed",
              !item.disabled && "cursor-pointer",
            )}
            onClick={handleItemClickFor(item)}
            disabled={item.disabled}
          >
            <div className="flex items-center justify-between">
              <span>{item.label}</span>
              {selectedKey === item.key && (
                <Check className="w-4 h-4 text-primary-500" />
              )}
            </div>
          </button>
        ))}
      </div>
    ));
  };

  return (
    <div ref={dropdownRef} className={cn("relative w-full", className)}>
      {/* Input */}
      <div className="relative">
        <input
          ref={inputRef}
          type="text"
          value={inputValue}
          onChange={handleInputChange}
          onFocus={handleInputFocus}
          onClick={handleInputClick}
          placeholder={isLoading ? loadingText : placeholder}
          disabled={disabled || isLoading}
          aria-label={ariaLabel}
          data-testid={testId}
          className={cn(
            "w-full h-10 px-4 pr-10 rounded-xl",
            "bg-background-glass backdrop-blur-xl border",
            "text-text-primary placeholder:text-text-tertiary",
            "transition-all duration-200",
            error
              ? "border-danger-DEFAULT/50 bg-danger-DEFAULT/5 focus:border-danger-DEFAULT/70 focus:bg-danger-DEFAULT/10"
              : "border-border-glass focus:border-primary-500/50 focus:bg-primary-500/5 focus:shadow-lg focus:shadow-primary-500/10",
            !error && "hover:border-primary-500/30 hover:bg-primary-500/3",
            "disabled:bg-background-surface disabled:border-border-subtle disabled:cursor-not-allowed disabled:opacity-50",
            inputClassName,
          )}
        />

        {/* Icons */}
        <div className="absolute right-3 top-1/2 transform -translate-y-1/2 flex items-center gap-1">
          {/* Loading Spinner */}
          {isLoading && (
            <div className="p-1">
              <div className="w-4 h-4 border-2 border-primary-500/30 border-t-primary-500 rounded-full animate-spin" />
            </div>
          )}

          {/* Error Icon */}
          {error && !isLoading && (
            <div className="p-1">
              <svg
                className="w-4 h-4 text-danger-DEFAULT"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-2.5L13.732 4c-.77-.833-1.964-.833-2.732 0L3.732 16.5c-.77.833.192 2.5 1.732 2.5z"
                />
              </svg>
            </div>
          )}

          {/* Clear Button */}
          {isClearable && inputValue && !isLoading && (
            <button
              type="button"
              onClick={handleClear}
              className="p-1 hover:bg-primary-500/10 rounded transition-colors"
              aria-label="Clear selection"
            >
              <svg
                className="w-4 h-4 text-text-tertiary"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M6 18L18 6M6 6l12 12"
                />
              </svg>
            </button>
          )}

          {/* Dropdown Toggle */}
          {!isLoading && (
            <button
              type="button"
              onClick={() => setIsOpen(!isOpen)}
              className={cn(
                "p-1 rounded transition-colors",
                "hover:bg-primary-500/10 focus:bg-primary-500/10 focus:outline-none",
                "disabled:opacity-50 disabled:cursor-not-allowed",
                isOpen && "bg-primary-500/10",
              )}
