interface LoadingStateProps {
  isLoading: boolean;
  children: React.ReactNode;
  fallback?: React.ReactNode;
  skeleton?: boolean;
  skeletonVariant?: "text" | "rectangular" | "circular" | "rounded";
  skeletonLines?: number;
  className?: string;
  spinnerSize?: "xs" | "small" | "medium" | "large" | "xl";
  spinnerVariant?: "default" | "dots" | "pulse" | "bars";
  loadingText?: string;
  overlay?: boolean;
}

export function LoadingState({
  isLoading,
  children,
  fallback,
  skeleton = false,
  skeletonVariant = "rectangular",
  skeletonLines = 3,
  className,
  spinnerSize = "medium",
  spinnerVariant = "default",
  loadingText,
  overlay = false,
}: LoadingStateProps) {
  if (!isLoading) {
    return <>{children}</>;
  }

  if (fallback) {
    return <>{fallback}</>;
  }

  if (skeleton) {
    return (
      <div className={cn("space-y-2", className)}>
        <SkeletonLoader
          variant={skeletonVariant}
          lines={skeletonLines}
          className="w-full"
        />
      </div>
    );
  }

  const loadingContent = (
    <div
      className={cn(
        "flex flex-col items-center justify-center gap-3 p-8",
        className,
      )}
    >
      <LoadingSpinner size={spinnerSize} variant={spinnerVariant} />
      {loadingText && (
        <p className="text-sm text-text-secondary animate-pulse">
          {loadingText}
        </p>
      )}
    </div>
  );

  if (overlay) {
    return (
      <div className="relative">
        {children}
        <div className="absolute inset-0 bg-background-glass/80 backdrop-blur-sm flex items-center justify-center z-10">
          {loadingContent}
        </div>
      </div>
    );
  }

  return loadingContent;
}

