import React, { useState, useRef, useEffect } from "react";

interface LazyImageProps {
  src: string;
  alt: string;
  className?: string;
  placeholder?: string;
  fallback?: string;
  width?: number;
  height?: number;
  quality?: number;
  priority?: boolean;
  onLoad?: () => void;
  onError?: () => void;
}

export const LazyImage: React.FC<LazyImageProps> = ({
  src,
  alt,
  className = "",
  placeholder = "data:image/svg+xml;base64,",
  fallback = "data:image/svg+xml;base64,",
  width,
  height,
  quality = 80,
  priority = false,
  onLoad,
  onError,
}) => {
  const [imageSrc, setImageSrc] = useState(placeholder);
  const [isLoaded, setIsLoaded] = useState(false);
  const [isInView, setIsInView] = useState(priority);
  const [hasError, setHasError] = useState(false);
  const imgRef = useRef<HTMLImageElement>(null);

  // Intersection Observer for lazy loading
  useEffect(() => {
    if (priority) return;

    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsInView(true);
          observer.disconnect();
        }
      },
      {
        threshold: 0.1,
        rootMargin: "50px",
      },
    );

    if (imgRef.current) {
      observer.observe(imgRef.current);
    }

    return () => observer.disconnect();
  }, [priority]);

  // Load image when in view
  useEffect(() => {
    if (!isInView || hasError) return;

    const img = new Image();

    img.onload = () => {
      setImageSrc(src);
      setIsLoaded(true);
      onLoad?.();
    };

    img.onerror = () => {
      setImageSrc(fallback);
      setHasError(true);
      onError?.();
    };

    // Add quality parameter if it's a supported image service
    const optimizedSrc = optimizeImageSrc(src, width, height, quality);
    img.src = optimizedSrc;
  }, [
    isInView,
    src,
    width,
    height,
    quality,
    fallback,
    onLoad,
    onError,
    hasError,
  ]);

  return (
    <img
      ref={imgRef}
      src={imageSrc}
      alt={alt}
      className={`transition-opacity duration-300 ${
        isLoaded ? "opacity-100" : "opacity-70"
      } ${className}`}
      width={width}
      height={height}
      loading={priority ? "eager" : "lazy"}
      decoding="async"
    />
  );
};

// Helper function to optimize image sources
function optimizeImageSrc(
  src: string,
  width?: number,
  height?: number,
  quality?: number,
): string {
  // If it's already a data URL or external service, return as is
  if (src.startsWith("data:") || src.startsWith("http")) {
    return src;
  }

  // For local images, you could add optimization logic here
  // For example, using a service like Cloudinary, ImageKit, or Next.js Image Optimization
  let optimizedSrc = src;

  // Example: Add query parameters for optimization
  const params = new URLSearchParams();
  if (width) params.set("w", width.toString());
  if (height) params.set("h", height.toString());
  if (quality) params.set("q", quality.toString());
  params.set("f", "auto"); // Auto format
  params.set("c", "limit"); // Limit dimensions

  if (params.toString()) {
    optimizedSrc += `?${params.toString()}`;
  }

  return optimizedSrc;
}

// Hook for preloading images
export const useImagePreload = (srcs: string[]) => {
  const [loadedImages, setLoadedImages] = useState<Set<string>>(new Set());
  const [loadingImages, setLoadingImages] = useState<Set<string>>(new Set());

  useEffect(() => {
    const preloadImages = async () => {
      const promises = srcs.map((src) => {
        if (loadedImages.has(src) || loadingImages.has(src))
          return Promise.resolve();

        setLoadingImages((prev) => new Set(prev).add(src));

        return new Promise<string>((resolve, reject) => {
          const img = new Image();
          img.onload = () => {
            setLoadedImages((prev) => new Set(prev).add(src));
            setLoadingImages((prev) => {
              const newSet = new Set(prev);
              newSet.delete(src);
              return newSet;
            });
            resolve(src);
          };
          img.onerror = () => {
            setLoadingImages((prev) => {
              const newSet = new Set(prev);
              newSet.delete(src);
              return newSet;
            });
            reject(new Error(`Failed to load image: ${src}`));
          };
          img.src = src;
        });
      });

      try {
        await Promise.allSettled(promises);
      } catch (error) {
        console.warn("Some images failed to preload:", error);
      }
    };

    preloadImages();
  }, [srcs, loadedImages, loadingImages]);

  return {
    loadedImages,
    loadingImages,
    isLoaded: (src: string) => loadedImages.has(src),
    isLoading: (src: string) => loadingImages.has(src),
  };
};

